sql:
SELECT COUNT(*) AS completed_entries_with_report
FROM imaging_entries
WHERE entry_status = 'completed' AND report_generated = 1;

SELECT method_name
FROM imaging_methods
WHERE recommended_frequency = 'annually';

SELECT exam_name
FROM examinations
WHERE priority = 'high';

SELECT MIN(resolution) AS min_resolution
FROM imaging_entries
WHERE entry_status = 'completed' AND report_generated = 1;

SELECT MIN(estimated_duration) AS min_duration
FROM examinations
WHERE exam_type = 'Routine';

SELECT entry_id
FROM imaging_entries
WHERE quality_score > 4.0;

SELECT first_name, last_name, years_of_experience
FROM radiologists
WHERE availability = 'full-time';

SELECT AVG(quality_score) AS overall_avg_quality_score
FROM imaging_entries
WHERE report_generated = 0;

